SELECT ts.title, ts.course_id AS courseId, ts.period, CASE WHEN ts.end_date IS NOT NULL AND ts.end_date < CURDATE() THEN 0 WHEN ts.start_date IS NOT NULL AND ts.start_date > CURDATE() THEN 0 ELSE ts.status END AS status, IFNULL(ts.date, '-') AS date, c.title AS courseName, ts.start_date AS startDate, ts.end_date AS endDate FROM test_schedule ts INNER JOIN course c ON ts.course_id = c.course_id WHERE (c.professor = #{loginId} OR c.sub_prof = #{loginId})
AND ts.course_id = #{course}
GROUP BY ts.title, ts.course_id, ts.period, ts.status, ts.end_date, ts.date, c.title ORDER BY ts.date DESC, ts.course_id DESC, ts.period DESC LIMIT #{pageSize} OFFSET #{pageIndex}

SELECT COUNT(*) FROM ( SELECT ts.course_id, ts.period FROM test_schedule ts INNER JOIN course c ON ts.course_id = c.course_id WHERE (c.professor = #{loginId} OR c.sub_prof = #{loginId})
AND ts.course_id = #{course}
GROUP BY ts.title, ts.course_id, ts.period, ts.status, ts.end_date, ts.date, c.title ) AS counted

SELECT COUNT(*)
FROM course c
WHERE c.course_id = #{courseId}

SELECT COUNT(*)
FROM course c
WHERE c.course_id = #{courseId}
  AND c.professor = #{loginId}

SELECT COUNT(*)
FROM test_schedule ts
WHERE ts.course_id = #{courseId}
  AND ts.title = #{title}
  AND ts.period = #{period}

